#include "stack.h"

void stack_init(Stack *stack) { stack->size = 0; }
bool stack_push(Stack *stack, int value) { if (stack->size == STACK_CAPACITY) return false; stack->values[stack->size++] = value; return true; }
bool stack_pop(Stack *stack, int *value) { if (stack->size == 0) return false; *value = stack->values[--stack->size]; return true; }
bool stack_is_empty(const Stack *stack) { return stack->size == 0; }

