#include "priority_queue.h"

void pq_init(PriorityQueue *queue) { stack_init(&queue->data); stack_init(&queue->scratch); }
bool pq_insert(PriorityQueue *queue, int priority) { return stack_push(&queue->data, priority); }

bool pq_extract_min(PriorityQueue *queue, int *priority) {
    if (stack_is_empty(&queue->data)) return false;

    int minimum;
    stack_pop(&queue->data, &minimum);

    int current;
    while (stack_pop(&queue->data, &current)) {
        if (current < minimum) {
            stack_push(&queue->scratch, minimum);
            minimum = current;
        } else {
            stack_push(&queue->scratch, current);
        }
    }

    while (stack_pop(&queue->scratch, &current)) {
        stack_push(&queue->data, current);
    }

    *priority = minimum;
    return true;
}

